css:
.print-heading {
    text-align: center;
    margin-bottom: 28px;
}

.print-heading h2 {
    margin: 0;
    font-size: 18pt;
    font-weight: 700;
    text-transform: uppercase;
}

.print-heading .document-name {
    margin-top: 8px;
    margin-bottom: 0;
    font-size: 10pt;
    color: #666;
}

.print-heading .outcome-label {
    margin-top: 6px;
    margin-bottom: 0;
    font-size: 12pt;
    font-weight: 600;
}

.nfa-section-heading {
    margin-top: 22px;
    margin-bottom: 10px;
    padding-bottom: 5px;
    border-bottom: 1px solid #b40000;
    font-size: 12pt;
    font-weight: 600;
}

.nfa-table {
    width: 100%;
    border-collapse: separate;
    border-spacing: 0;
    border: 1px solid #ddd;
    border-radius: 8px;
    overflow: hidden;
    margin-bottom: 20px;
}

.nfa-table th,
.nfa-table td {
    padding: 8px;
    vertical-align: top;
}

.nfa-table th {
    background-color: #f5f5f5;
    border-bottom: 1px solid #ddd;
    font-weight: 600;
    text-align: left;
}

.nfa-table td {
    border-bottom: 1px solid #ddd;
    border-right: 1px solid #ddd;
}

.nfa-table td:last-child,
.nfa-table th:last-child {
    border-right: none;
}

.nfa-table tbody tr:last-child td {
    border-bottom: none;
}

.nfa-table tbody tr:nth-child(odd) {
    background-color: #fafafa;
}

.nfa-summary {
    margin: 12px 0 20px;
    padding: 12px;
    border: 1px solid #ddd;
    border-left: 4px solid #b40000;
    border-radius: 4px;
    background-color: #fafafa;
}

.nfa-summary p {
    margin: 0 0 8px;
}

.nfa-summary p:last-child {
    margin-bottom: 0;
}

.nfa-outcome-box {
    margin: 18px 0;
    padding: 14px;
    border: 2px solid #333;
    border-radius: 6px;
    text-align: center;
}

.nfa-outcome-box .label {
    margin-bottom: 5px;
    font-size: 10pt;
    text-transform: uppercase;
    color: #666;
}

.nfa-outcome-box .value {
    font-size: 15pt;
    font-weight: 700;
}

.signatures table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 30px;
}

.signatures td {
    width: 50%;
    border: none;
    padding: 20px 10px 20px 0;
    vertical-align: top;
}

.signatures td:last-child {
    padding-right: 0;
}

.signatures p {
    margin: 0;
    font-size: 11pt;
}

.signature-space {
    height: 35px;
}

.no-data {
    color: #777;
    font-style: italic;
}

@page {
    @bottom-right {
        content: "Page " counter(page) " of " counter(pages);
        font-size: 10pt;
        color: #999;
    }
}
